import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';
import { ProjectService, TaskService, UserService, DepartmentService, TeamService } from '../../../core/services/api.services';
import { ToastService } from '../../../core/services/toast.service';
import { Project, Task, TaskAssignment, Department, Team, UtilizationDTO } from '../../../core/models';

@Component({ selector: 'app-project-detail', templateUrl: './project-detail.component.html' })
export class ProjectDetailComponent implements OnInit {
  project: Project | null = null;
  tasks: Task[] = [];
  assignments: Map<number, TaskAssignment[]> = new Map();
  loading = true;
  showTaskForm = false;
  showAssignForm = false;
  editingTask: Task | null = null;
  assigningTask: Task | null = null;
  showDeleteConfirm = false;
  deletingTask: Task | null = null;
  get today(): string { return new Date().toISOString().split('T')[0]; }

  departments: Department[] = [];
  teams: Team[] = [];
  filteredTeams: Team[] = [];

  taskForm: any = {
    title: '', description: '', priority: 'MEDIUM', estimatedHours: 8,
    requiredEmployees: 1, dueDate: '', status: 'PENDING',
    departmentId: null, teamId: null
  };
  availableEmployees: UtilizationDTO[] = [];
  selectedEmployeeId: number | null = null;
  assignNotes = '';
  savingTask = false;
  savingAssign = false;

  constructor(
    private route: ActivatedRoute,
    public router: Router,
    public auth: AuthService,
    private projectService: ProjectService,
    private taskService: TaskService,
    private userService: UserService,
    private deptService: DepartmentService,
    private teamService: TeamService,
    private toast: ToastService
  ) {}

  ngOnInit(): void {
    this.route.params.subscribe(p => this.load(+p['id']));
    this.deptService.getAll().subscribe(r => { if (r.success) this.departments = r.data; });
    this.teamService.getAll().subscribe(r => { if (r.success) this.teams = r.data; });
  }

  load(id: number): void {
    this.loading = true;
    this.projectService.getById(id).subscribe(r => {
      if (r.success) { this.project = r.data; this.loadTasks(); }
      else this.loading = false;
    });
  }

  loadTasks(): void {
    this.taskService.getByProject(this.project!.id).subscribe(r => {
      if (r.success) { this.tasks = r.data; this.loadAssignments(); }
      this.loading = false;
    });
  }

  loadAssignments(): void {
    this.tasks.forEach(t => {
      this.taskService.getAssignmentsForTask(t.id).subscribe(r => {
        if (r.success) this.assignments.set(t.id, r.data);
      });
    });
  }

  getAssignments(taskId: number): TaskAssignment[] { return this.assignments.get(taskId) || []; }

  onDeptChange(): void {
    this.taskForm.teamId = null;
    this.filteredTeams = this.teams.filter(t => t.department?.id === +this.taskForm.departmentId);
  }

  openTaskForm(task?: Task): void {
    this.editingTask = task || null;
    if (task) {
      this.taskForm = {
        title: task.title, description: task.description || '',
        priority: task.priority, estimatedHours: task.estimatedHours || 8,
        requiredEmployees: task.requiredEmployees || 1,
        dueDate: task.dueDate || '', status: task.status,
        departmentId: task.department?.id || null,
        teamId: task.team?.id || null
      };
    } else {
      this.taskForm = {
        title: '', description: '', priority: 'MEDIUM', estimatedHours: 8,
        requiredEmployees: 1, dueDate: '', status: 'PENDING',
        // PM must select a dept; dept heads pre-fill their own dept
        departmentId: this.auth.isDeptHead ? this.auth.deptId : null,
        teamId: this.auth.isTeamLead ? this.auth.teamId : null
      };
    }
    if (this.taskForm.departmentId) {
      this.filteredTeams = this.teams.filter(t => t.department?.id === +this.taskForm.departmentId);
    } else {
      this.filteredTeams = [];
    }
    this.showTaskForm = true;
  }

  saveTask(): void {
    if (!this.taskForm.title) return;
    // PM must assign to a department
    if (this.auth.isPM && !this.taskForm.departmentId) {
      this.toast.showError('Please select a department to assign this task to.');
      return;
    }
    this.savingTask = true;
    const data: any = {
      ...this.taskForm,
      projectId: this.project!.id,
      departmentId: this.taskForm.departmentId ? +this.taskForm.departmentId : null,
      // PM does not set team — dept head does that via sub-tasks
      teamId: this.auth.isPM ? null : (this.taskForm.teamId ? +this.taskForm.teamId : null)
    };
    const obs = this.editingTask
      ? this.taskService.update(this.editingTask.id, data)
      : this.taskService.create(data);
    obs.subscribe({
      next: r => {
        this.savingTask = false;
        if (r.success) { 
          this.showTaskForm = false; this.loadTasks(); 
          this.toast.showSuccess(this.editingTask ? 'Task updated successfully' : 'Task created successfully');
        } else { this.toast.showError(r.message || 'Failed to save task'); }
      },
      error: err => { this.savingTask = false; this.toast.showError(err.error?.message || 'Error saving task'); }
    });
  }

  openAssign(task: Task): void {
    this.assigningTask = task;
    this.selectedEmployeeId = null;
    this.assignNotes = '';
    const utilObs = this.auth.isPM ? this.userService.getAllUtilization()
      : this.auth.isDeptHead ? this.userService.getDeptUtilization(this.auth.deptId)
      : this.userService.getTeamUtilization(this.auth.teamId);
    utilObs.subscribe(r => {
      if (r.success) {
        const deptId = task.department?.id;
        const estimatedHours = task.estimatedHours || 0;
        this.availableEmployees = r.data.filter(u => {
          const inDept = deptId ? u.departmentId === deptId : true;
          const canTakeTask = (u.allocatedHours + estimatedHours) <= u.maxCapacityHours;
          return inDept && canTakeTask;
        });
      }
    });
    this.showAssignForm = true;
  }

  saveAssign(): void {
    if (!this.selectedEmployeeId) return;
    this.savingAssign = true;
    this.taskService.assign({
      taskId: this.assigningTask!.id, employeeId: this.selectedEmployeeId,
      assignedById: this.auth.userId, notes: this.assignNotes
    }).subscribe({
      next: r => {
        this.savingAssign = false;
        if (r.success) { 
          this.showAssignForm = false; this.loadAssignments(); 
          this.toast.showSuccess('Task assigned successfully');
        } else { this.toast.showError(r.message || 'Failed to assign task'); }
      },
      error: err => { this.savingAssign = false; this.toast.showError(err.error?.message || 'Error assigning task'); }
    });
  }

  confirmDeleteTask(task: Task): void { this.deletingTask = task; this.showDeleteConfirm = true; }
  deleteTask(): void {
    if (!this.deletingTask) return;
    this.taskService.delete(this.deletingTask.id).subscribe({
      next: r => {
        this.showDeleteConfirm = false;
        if (r.success) { this.loadTasks(); this.toast.showSuccess('Task deleted successfully'); }
        else { this.toast.showError(r.message || 'Failed to delete task'); }
      },
      error: err => { this.showDeleteConfirm = false; this.toast.showError(err.error?.message || 'Error deleting task'); }
    });
  }

  removeAssignment(assignId: number): void {
    this.taskService.removeAssignment(assignId).subscribe({
      next: r => {
        if (r.success) { this.loadAssignments(); this.toast.showSuccess('Assignment removed successfully'); }
        else { this.toast.showError(r.message || 'Failed to remove assignment'); }
      },
      error: err => this.toast.showError(err.error?.message || 'Error removing assignment')
    });
  }

  deleteProject(): void {
    if (!this.project) return;
    this.projectService.delete(this.project.id).subscribe({
      next: r => {
        if (r.success) { this.toast.showSuccess('Project deleted successfully'); this.router.navigate(['/projects']); }
        else { this.toast.showError(r.message || 'Failed to delete project'); }
      },
      error: err => this.toast.showError(err.error?.message || 'Error deleting project')
    });
  }

  getTaskBadge(s: string): string {
    const m: any = { PENDING:'badge-yellow', IN_PROGRESS:'badge-blue', REVIEW:'badge-purple', COMPLETED:'badge-green', CANCELLED:'badge-gray' };
    return m[s] || 'badge-gray';
  }
  getPriorityBadge(s: string): string {
    const m: any = { LOW:'badge-gray', MEDIUM:'badge-blue', HIGH:'badge-yellow', CRITICAL:'badge-red' };
    return m[s] || 'badge-gray';
  }
  getUtilClass(s: string): string {
    return s === 'OVERLOADED' ? 'overload' : s === 'OPTIMAL' ? 'optimal' : 'underutil';
  }
}
<div class="fade-in" *ngIf="!loading && project">
  <!-- Header -->
  <div class="page-header">
    <div style="display:flex;align-items:center;gap:12px">
      <button class="btn btn-outline btn-sm" (click)="router.navigate(['/projects'])">← Back</button>
      <div>
        <div class="page-title">{{ project!.name }}</div>
        <div class="page-subtitle">{{ project!.description }}</div>
      </div>
    </div>
    <div style="display:flex;gap:8px" *ngIf="auth.isPM">
      <button class="btn btn-danger btn-sm" (click)="deleteProject()">Delete Project</button>
    </div>
  </div>

  <!-- Project Stats -->
  <div class="stats-grid" style="margin-bottom:24px">
    <div class="stat-card">
      <div class="stat-icon blue">◈</div>
      <div><div class="stat-label">Status</div><div class="stat-value" style="font-size:14px">{{ project!.status }}</div></div>
    </div>
    <div class="stat-card">
      <div class="stat-icon yellow">✓</div>
      <div><div class="stat-label">Total Tasks</div><div class="stat-value">{{ tasks.length }}</div><div class="stat-sub">{{ tasks | countByStatus:'COMPLETED' }} completed</div></div>
    </div>
    <div class="stat-card">
      <div class="stat-icon green">⊕</div>
      <div><div class="stat-label">Deadline</div><div class="stat-value" style="font-size:14px">{{ project!.deadline ? (project!.deadline | date:'MMM d, y') : 'None' }}</div></div>
    </div>
    <div class="stat-card">
      <div class="stat-icon purple">★</div>
      <div><div class="stat-label">Priority</div><div class="stat-value" style="font-size:14px">{{ project!.priority }}</div></div>
    </div>
  </div>

  <!-- Tasks Section -->
  <div class="card">
    <div class="card-header">
      <div class="card-title">Tasks</div>
      <button *ngIf="auth.canManageTasks()" class="btn btn-primary btn-sm" (click)="openTaskForm()">+ Add Task</button>
    </div>

    <div *ngIf="tasks.length === 0" class="empty-state" style="padding:48px">
      <div class="empty-icon">✓</div>
      <div class="empty-title">No tasks yet</div>
      <div class="empty-desc" *ngIf="auth.canManageTasks()">Add the first task to this project</div>
    </div>

    <div *ngFor="let task of tasks" class="task-card"
      [class.task-completed]="task.status === 'COMPLETED'">
      <div class="task-card-header">
        <div style="flex:1">
          <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">
            <span style="font-weight:700;font-size:15px">{{ task.title }}</span>
            <span class="badge" [ngClass]="getTaskBadge(task.status)">{{ task.status }}</span>
            <span class="badge" [ngClass]="getPriorityBadge(task.priority)">{{ task.priority }}</span>
          </div>
          <div style="font-size:13px;color:var(--text-muted);margin-top:4px">
            {{ task.description }}
            <span *ngIf="task.dueDate" style="margin-left:8px">📅 Due {{ task.dueDate | date:'MMM d' }}</span>
            <span style="margin-left:8px">⏱ {{ task.estimatedHours }}h estimated</span>
          </div>
        </div>
        <div style="display:flex;gap:6px;align-items:center" *ngIf="auth.canManageTasks()">
          <button class="btn btn-icon btn-sm" (click)="openAssign(task)" title="Assign Employee">👤</button>
          <button class="btn btn-icon btn-sm" (click)="openTaskForm(task)" title="Edit">✏</button>
          <button class="btn btn-icon btn-sm btn-danger-ghost" (click)="confirmDeleteTask(task)" title="Delete">✕</button>
        </div>
      </div>

      <!-- Assignees -->
      <div *ngIf="getAssignments(task.id).length > 0" style="margin-top:12px;padding-top:12px;border-top:1px solid var(--border)">
        <div style="font-size:11px;font-weight:600;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:8px">Assigned To</div>
        <div style="display:flex;flex-wrap:wrap;gap:8px">
          <div *ngFor="let a of getAssignments(task.id)" class="assignee-chip">
            <span class="avatar-xs">{{ a.employee?.firstName?.[0] }}{{ a.employee?.lastName?.[0] }}</span>
            <span>{{ a.employee?.firstName }} {{ a.employee?.lastName }}</span>
            <span style="font-family:'DM Mono',monospace;font-size:11px;color:var(--text-muted)">{{ a.completionPercentage }}%</span>
            <button *ngIf="auth.canManageTasks()" class="chip-remove" (click)="removeAssignment(a.id)">×</button>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>

<div *ngIf="loading" class="loading-wrap"><div class="spinner"></div></div>

<!-- Task Form Modal -->
<div *ngIf="showTaskForm" class="modal-overlay" (click)="showTaskForm=false">
  <div class="modal" (click)="$event.stopPropagation()">
    <div class="modal-header">
      <div class="modal-title">{{ editingTask ? 'Edit Task' : 'New Task' }}</div>
      <button class="modal-close" (click)="showTaskForm=false">×</button>
    </div>
    <div class="modal-body">
      <div class="form-group">
        <label class="form-label">Title *</label>
        <input class="form-control" [(ngModel)]="taskForm.title" placeholder="Task title">
      </div>

      <div class="form-group" *ngIf="utilizationSummary">
        <label class="form-label">Current Team Capacity Overview</label>
        <div style="font-size:12px;color:var(--text-secondary);background:var(--bg-alt);padding:8px;border-radius:4px;border:1px solid var(--border)">
          {{ utilizationSummary }}
        </div>
      </div>
      <div class="form-group">
        <label class="form-label">Description</label>
        <textarea class="form-control" [(ngModel)]="taskForm.description" rows="3" placeholder="What needs to be done..."></textarea>
      </div>

      <!-- PM: must pick a department. Dept head & team lead: no dept picker (auto-set) -->
      <div class="form-group" *ngIf="auth.isPM">
        <label class="form-label">Assign to Department *</label>
        <select class="form-control" [(ngModel)]="taskForm.departmentId" (ngModelChange)="onDeptChange()">
          <option [ngValue]="null">— Select department —</option>
          <option *ngFor="let d of departments" [ngValue]="d.id">{{ d.name }}</option>
        </select>
        <div style="font-size:11px;color:#64748b;margin-top:4px">
          Department heads will break this task into sub-tasks for their teams.
        </div>
      </div>

      <!-- Dept head: pick which team handles this task -->
      <div class="form-group" *ngIf="auth.isDeptHead">
        <label class="form-label">Assign to Team (optional)</label>
        <select class="form-control" [(ngModel)]="taskForm.teamId">
          <option [ngValue]="null">No specific team yet</option>
          <option *ngFor="let t of filteredTeams" [ngValue]="t.id">{{ t.name }}</option>
        </select>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">
        <div class="form-group">
          <label class="form-label">Priority</label>
          <select class="form-control" [(ngModel)]="taskForm.priority">
            <option value="LOW">Low</option><option value="MEDIUM">Medium</option>
            <option value="HIGH">High</option><option value="CRITICAL">Critical</option>
          </select>
        </div>
        <div class="form-group">
          <label class="form-label">Status</label>
          <select class="form-control" [(ngModel)]="taskForm.status">
            <option value="PENDING">Pending</option><option value="IN_PROGRESS">In Progress</option>
            <option value="REVIEW">Review</option><option value="COMPLETED">Completed</option>
          </select>
        </div>
        <div class="form-group">
          <label class="form-label">Estimated Hours</label>
          <input type="number" class="form-control" [(ngModel)]="taskForm.estimatedHours" min="1">
        </div>
        <div class="form-group">
          <label class="form-label">Due Date</label>
          <input type="date" class="form-control" [(ngModel)]="taskForm.dueDate" [min]="today">
        </div>
      </div>
    </div>
    <div class="modal-footer">
      <button class="btn btn-outline" (click)="showTaskForm=false">Cancel</button>
      <button class="btn btn-primary" (click)="saveTask()" [disabled]="savingTask || !taskForm.title">
        {{ savingTask ? 'Saving...' : (editingTask ? 'Update Task' : 'Create Task') }}
      </button>
    </div>
  </div>
</div>

<!-- Assign Modal -->
<div *ngIf="showAssignForm" class="modal-overlay" (click)="showAssignForm=false">
  <div class="modal" (click)="$event.stopPropagation()">
    <div class="modal-header">
      <div class="modal-title">Assign Employee — {{ assigningTask?.title }}</div>
      <button class="modal-close" (click)="showAssignForm=false">×</button>
    </div>
    <div class="modal-body">
      <div class="form-group">
        <label class="form-label">Select Employee</label>
        <select class="form-control" [(ngModel)]="selectedEmployeeId">
          <option [ngValue]="null">Choose employee...</option>
          <option *ngFor="let u of availableEmployees" [ngValue]="u.userId">
            {{ u.name }} — {{ u.utilizationPercent | number:'1.0-0' }}% utilized ({{ u.utilizationStatus }})
          </option>
        </select>
      </div>
      <div class="form-group">
        <label class="form-label">Notes</label>
        <textarea class="form-control" [(ngModel)]="assignNotes" rows="2" placeholder="Any specific instructions..."></textarea>
      </div>
    </div>
    <div class="modal-footer">
      <button class="btn btn-outline" (click)="showAssignForm=false">Cancel</button>
      <button class="btn btn-primary" (click)="saveAssign()" [disabled]="savingAssign || !selectedEmployeeId">
        {{ savingAssign ? 'Assigning...' : 'Assign' }}
      </button>
    </div>
  </div>
</div>

<!-- Delete Confirm -->
<div *ngIf="showDeleteConfirm" class="modal-overlay" (click)="showDeleteConfirm=false">
  <div class="modal modal-sm" (click)="$event.stopPropagation()">
    <div class="modal-header"><div class="modal-title" style="color:var(--danger)">Delete Task</div></div>
    <div class="modal-body"><p>Delete "<strong>{{ deletingTask?.title }}</strong>"? This cannot be undone.</p></div>
    <div class="modal-footer">
      <button class="btn btn-outline" (click)="showDeleteConfirm=false">Cancel</button>
      <button class="btn btn-danger" (click)="deleteTask()">Delete</button>
    </div>
  </div>
</div>
